// hooks/useS3RealtimeData.js
import { useState, useEffect, useCallback, useRef } from 'react';
import { fetchAllJsonFiles, mapS3DataToUIFormat } from './s3';

export const useS3RealtimeData = (initialData = [], refreshInterval = 10000) => {
    const [data, setData] = useState(initialData);
    const [loading, setLoading] = useState(false);
    const [lastUpdate, setLastUpdate] = useState(null);
    const [error, setError] = useState(null);
    const intervalRef = useRef(null);

    // Функция для дедупликации данных по имени файла
    const deduplicateData = useCallback((existingData, newData) => {
        const dataMap = new Map();

        // Добавляем существующие данные (используем fileName как ключ)
        existingData.forEach(item => {
            if (!dataMap.has(item.fileName)) {
                dataMap.set(item.fileName, item);
            } else {
                // Если дубликат, проверяем дату и оставляем более новую
                const existing = dataMap.get(item.fileName);
                const existingDate = new Date(existing.date.split(' ')[0].split('.').reverse().join('-'));
                const newDate = new Date(item.date.split(' ')[0].split('.').reverse().join('-'));
                if (newDate > existingDate) {
                    dataMap.set(item.fileName, item);
                }
            }
        });

        // Добавляем новые данные (более новые заменяют старые)
        newData.forEach(item => {
            const existing = dataMap.get(item.fileName);
            if (!existing) {
                dataMap.set(item.fileName, item);
            } else {
                const existingDate = new Date(existing.date.split(' ')[0].split('.').reverse().join('-'));
                const newDate = new Date(item.date.split(' ')[0].split('.').reverse().join('-'));
                if (newDate > existingDate) {
                    dataMap.set(item.fileName, item);
                }
            }
        });

        // Преобразуем обратно в массив и сортируем по дате (новые сверху)
        return Array.from(dataMap.values()).sort((a, b) => {
            try {
                const dateA = new Date(a.date.split(' ')[0].split('.').reverse().join('-') + ' ' + (a.date.split(' ')[1] || '00:00'));
                const dateB = new Date(b.date.split(' ')[0].split('.').reverse().join('-') + ' ' + (b.date.split(' ')[1] || '00:00'));
                return dateB - dateA;
            } catch (e) {
                return 0;
            }
        });
    }, []);

    // Функция загрузки данных из S3
    const loadDataFromS3 = useCallback(async () => {
        setLoading(true);
        setError(null);

        try {
            console.log('Загрузка данных из S3...');
            const s3Reports = await fetchAllJsonFiles();

            if (s3Reports.length > 0) {
                console.log(`Загружено ${s3Reports.length} файлов из S3`);
                // Маппинг данных в формат UI
                const mappedData = s3Reports.map(report => mapS3DataToUIFormat(report));

                // Дедупликация с существующими данными
                setData(prevData => deduplicateData(prevData, mappedData));
                setLastUpdate(new Date());
            } else {
                console.log('Новых JSON файлов не найдено');
            }
        } catch (err) {
            console.error('Ошибка при загрузке данных из S3:', err);
            setError(err.message);
        } finally {
            setLoading(false);
        }
    }, [deduplicateData]);

    // Запускаем периодическую загрузку
    useEffect(() => {
        // Первоначальная загрузка
        loadDataFromS3();

        // Настраиваем интервал
        intervalRef.current = setInterval(() => {
            loadDataFromS3();
        }, refreshInterval);

        // Очищаем интервал при размонтировании
        return () => {
            if (intervalRef.current) {
                clearInterval(intervalRef.current);
            }
        };
    }, [loadDataFromS3, refreshInterval]);

    // Функция для ручного обновления
    const refresh = useCallback(() => {
        loadDataFromS3();
    }, [loadDataFromS3]);

    return {
        data,
        loading,
        lastUpdate,
        error,
        refresh
    };
};