import React, { useState, createContext, useContext } from 'react';
import { Layout, Typography, Card, Row, Col, Upload, message, Tabs, Space, Form, Input, Button, Alert, Spin, Progress } from 'antd';
import { CloudUploadOutlined, FileTextOutlined, RobotOutlined, LoginOutlined, LogoutOutlined, UploadOutlined } from '@ant-design/icons';
import Dashboard from './components/Dashboard';
import './App.css';

const { Header, Content } = Layout;
const { Title } = Typography;

// Создаем контекст для глобального доступа к presignedUrl
const AppContext = createContext();

// Улучшенный компонент загрузки файлов
function FileUploader({ onUploadSuccess, uploadedFile, setUploadedFile }) {
  const { presignedUrl } = useContext(AppContext);
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const fileInputRef = React.useRef();

  const uploadToS3 = async (file) => {
    if (!presignedUrl) {
      message.error('Ошибка: нет URL для загрузки');
      return false;
    }

    setUploading(true);
    setUploadProgress(0);

    try {
      // Используем fetch вместо XHR для лучшей совместимости с CORS
      const response = await fetch(presignedUrl, {
        method: 'PUT',
        headers: {
          'Content-Type': file.type || 'application/octet-stream',
          // Добавляем явное разрешение CORS
          'Origin': window.location.origin,
        },
        body: file,
        mode: 'cors', // Явно указываем CORS режим
        credentials: 'omit', // Не отправляем credentials для S3
      });

      if (!response.ok) {
        throw new Error(`Ошибка загрузки: ${response.status} ${response.statusText}`);
      }

      message.success('Файл успешно загружен!');
      if (onUploadSuccess) {
        onUploadSuccess({
          name: file.name,
          size: file.size,
          type: file.type,
          lastModified: file.lastModified
        });
      }
      return true;
    } catch (error) {
      console.error('Upload error:', error);

      // Более детальная диагностика ошибки CORS
      if (error.message.includes('fetch') || error.name === 'TypeError') {
        message.error('Ошибка CORS: сервер S3 не настроен для приема запросов с этого домена. Проверьте настройки CORS в бакете.');
      } else {
        message.error(`Ошибка загрузки: ${error.message}`);
      }
      return false;
    } finally {
      setUploading(false);
      setUploadProgress(0);
    }
  };

  const handleFileSelect = async (event) => {
    const file = event.target.files[0];
    if (!file) return;

    // Проверка типа файла
    const validTypes = ['text/plain', 'application/json', 'audio/mpeg', 'audio/wav', 'audio/mp3'];
    if (!validTypes.includes(file.type) && !file.name.endsWith('.txt') && !file.name.endsWith('.json')) {
      message.error('Пожалуйста, загружайте файлы форматов: .txt, .json, .mp3, .wav');
      return;
    }

    // Проверка размера (например, 10MB)
    if (file.size > 10 * 1024 * 1024) {
      message.error('Файл слишком большой. Максимальный размер: 10MB');
      return;
    }

    setUploadedFile(file);
  };

  const handleUpload = async () => {
    if (!uploadedFile) {
      message.warning('Пожалуйста, выберите файл');
      return;
    }

    await uploadToS3(uploadedFile);
  };

  return (
    <Card title="Загрузка файла разговора" style={{ marginTop: 20 }}>
      <Space direction="vertical" size="large" style={{ width: '100%' }}>
        <Alert
          message="Информация о загрузке"
          description={`Файлы будут загружены через защищенное соединение. Presigned URL действителен в течение 5 минут.`}
          type="info"
          showIcon
        />

        <div>
          <input
            ref={fileInputRef}
            type="file"
            onChange={handleFileSelect}
            accept=".txt,.json,.mp3,.wav"
            disabled={uploading}
            style={{ display: 'none' }}
            id="file-input"
          />
          <Space>
            <Button
              icon={<UploadOutlined />}
              onClick={() => fileInputRef.current.click()}
              disabled={uploading}
            >
              Выбрать файл
            </Button>
            <Button
              type="primary"
              onClick={handleUpload}
              loading={uploading}
              disabled={!uploadedFile || uploading}
            >
              Загрузить на сервер
            </Button>
          </Space>
          {uploadedFile && (
            <div style={{ marginTop: 16 }}>
              <strong>Выбран файл:</strong> {uploadedFile.name} (
              {(uploadedFile.size / 1024).toFixed(2)} KB)
            </div>
          )}
        </div>

        {uploading && (
          <div>
            <Progress percent={uploadProgress} status="active" />
            <div style={{ textAlign: 'center', marginTop: 8 }}>
              Загрузка... {uploadProgress}%
            </div>
          </div>
        )}
      </Space>
    </Card>
  );
}

// Улучшенная форма логина
function LoginForm({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!email || !password) {
      setError('Пожалуйста, заполните все поля');
      return;
    }

    setLoading(true);
    setError('');

    try {
      // Добавляем таймаут для запроса
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 30000);

      const response = await fetch('https://functions.yandexcloud.net/d4ep3celol7cbt8bohe8', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          email: email.trim(),
          password: password
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const data = await response.json();

      // ВАЖНО: В реальном приложении здесь должна быть проверка JWT токена
      // Сейчас проверяем наличие presignedUrl
      if (data && data.presignedUrl && typeof data.presignedUrl === 'string' && data.presignedUrl.startsWith('https://')) {
        // Сохраняем presignedUrl в глобальное состояние
        onLogin(true, data.presignedUrl);
        message.success('Успешный вход!');

        // Оповещаем о времени действия URL
        if (data.expiresIn) {
          message.info(`Ссылка для загрузки действительна ${data.expiresIn} секунд`, 3);
        }
      } else {
        setError('Неверный email или пароль');
        message.error('Ошибка авторизации');
      }
    } catch (err) {
      console.error('Auth error:', err);
      if (err.name === 'AbortError') {
        setError('Превышено время ожидания ответа от сервера');
      } else {
        setError(`Ошибка соединения: ${err.message}`);
      }
      message.error('Не удалось подключиться к серверу');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{
      maxWidth: 400,
      margin: '100px auto',
      padding: 24,
      background: 'white',
      borderRadius: 8,
      boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
    }}>
      <div style={{ textAlign: 'center', marginBottom: 24 }}>
        <RobotOutlined style={{ fontSize: 48, color: '#1890ff' }} />
        <Title level={2}>Вход в систему</Title>
        <Alert
          message="⚠️ Демо-режим"
          description=""
          type="warning"
          showIcon
          style={{ marginTop: 16 }}
        />
      </div>

      <form onSubmit={handleSubmit}>
        <Form.Item>
          <Input
            placeholder="Email"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            size="large"
            prefix={<LoginOutlined />}
            disabled={loading}
          />
        </Form.Item>

        <Form.Item>
          <Input.Password
            placeholder="Пароль"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            size="large"
            disabled={loading}
          />
        </Form.Item>

        {error && (
          <Alert message={error} type="error" showIcon style={{ marginBottom: 16 }} />
        )}

        <Button type="primary" htmlType="submit" size="large" block loading={loading}>
          Войти
        </Button>

        <div style={{ marginTop: 16, fontSize: 12, color: '#999', textAlign: 'center' }}>
          Для теста: только .mp3 файлы
        </div>
      </form>
    </div>
  );
}

// Основной компонент приложения
function AuthenticatedApp({ onLogout }) {
  const [activeTab, setActiveTab] = useState('upload');
  const [uploadedFile, setUploadedFile] = useState(null);
  const { presignedUrl, setPresignedUrl } = useContext(AppContext);

  const handleUploadSuccess = (fileInfo) => {
    setUploadedFile(fileInfo);
    message.success('Файл успешно загружен! Результаты проверки появятся в дашборде');
    // setTimeout(() => {
    //   setActiveTab('dashboard');
    // }, 2000);
  };

  // Проверяем, не истек ли presigned URL
  React.useEffect(() => {
    if (presignedUrl) {
      // Можно добавить проверку валидности URL
      console.log('Presigned URL is set and ready for uploads');
    }
  }, [presignedUrl]);

  const items = [
    {
      key: 'upload',
      label: (
        <Space>
          <CloudUploadOutlined />
          Загрузка разговора
        </Space>
      ),
      children: (
        <FileUploader
          onUploadSuccess={handleUploadSuccess}
          uploadedFile={uploadedFile}
          setUploadedFile={setUploadedFile}
        />
      ),
    },
    {
      key: 'dashboard',
      label: (
        <Space>
          <FileTextOutlined />
          Дашборд проверок
        </Space>
      ),
      children: <Dashboard lastUploadedFile={uploadedFile} />,
    },
  ];

  return (
    <>
      <Header className="app-header">
        <div className="header-content">
          <div className="logo-container">
            <RobotOutlined className="logo-icon" />
            <Title level={3} className="logo-title" style={{ margin: 0, color: 'white' }}>
              Система оценки качества обслуживания
            </Title>
          </div>
          <Button
            icon={<LogoutOutlined />}
            onClick={() => {
              onLogout();
              setPresignedUrl(null); // Очищаем URL при выходе
            }}
            style={{ marginLeft: 'auto' }}
          >
            Выйти
          </Button>
        </div>
      </Header>
      <Content style={{ padding: '50px', background: '#f0f2f5' }}>
        <div style={{ maxWidth: 1400, margin: '0 auto' }}>
          <Tabs activeKey={activeTab} onChange={setActiveTab} items={items} size="large" />
        </div>
      </Content>
    </>
  );
}

// Главный компонент App
function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [presignedUrl, setPresignedUrl] = useState(null);

  const handleLogin = (status, url) => {
    setIsAuthenticated(status);
    if (url) {
      setPresignedUrl(url);
      // Сохраняем в localStorage для отладки (не рекомендуется для продакшена)
      console.log('Presigned URL получен:', url.substring(0, 100) + '...');
    }
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setPresignedUrl(null);
    message.info('Вы вышли из системы');
  };

  // Значение для контекста
  const contextValue = {
    presignedUrl,
    setPresignedUrl,
    isAuthenticated
  };

  return (
    <AppContext.Provider value={contextValue}>
      <Layout className="layout">
        {!isAuthenticated ? (
          <LoginForm onLogin={handleLogin} />
        ) : (
          <AuthenticatedApp onLogout={handleLogout} />
        )}
      </Layout>
    </AppContext.Provider>
  );
}

export default App;