// services/yandexS3Service.js

const BUCKET_URL = 'https://diplom-2026.storage.yandexcloud.net';
const REPORTS_FOLDER = 'reports/';
const MANIFEST_URL = `${BUCKET_URL}/reports/manifests.json`;

// Основная функция - загружает все JSON файлы через манифест
export const fetchAllJsonFiles = async () => {
    try {
        console.log('📋 Загружаем манифест...');

        // 1. Загружаем манифест со списком файлов
        const manifestResponse = await fetch(MANIFEST_URL);

        if (!manifestResponse.ok) {
            throw new Error(`Не удалось загрузить манифест: ${manifestResponse.status}`);
        }

        const manifest = await manifestResponse.json();

        // Поддерживаем разные форматы манифеста
        let fileList = [];
        if (Array.isArray(manifest)) {
            fileList = manifest;
        } else if (manifest.files && Array.isArray(manifest.files)) {
            fileList = manifest.files;
        } else {
            throw new Error('Неверный формат манифеста');
        }

        console.log(`📋 В манифесте найдено ${fileList.length} файлов`);

        if (fileList.length === 0) {
            console.warn('⚠️ Манифест пуст');
            return [];
        }

        // 2. Загружаем каждый файл из манифеста
        const reports = [];
        for (let i = 0; i < fileList.length; i++) {
            const filePath = fileList[i];
            try {
                console.log(`📥 Загрузка ${i + 1}/${fileList.length}: ${filePath}`);
                const report = await loadSingleFile(filePath);
                if (report) {
                    reports.push(report);
                }
            } catch (err) {
                console.error(`❌ Ошибка загрузки ${filePath}:`, err);
            }
        }

        console.log(`✅ Успешно загружено ${reports.length} из ${fileList.length} файлов`);
        return reports;

    } catch (error) {
        console.error('❌ Ошибка при загрузке файлов из S3:', error);
        console.error('   Проверьте, что файл manifests.json существует в корне бакета');
        return [];
    }
};

// Загрузка одного файла по пути
const loadSingleFile = async (filePath) => {
    try {
        // Если путь уже полный URL, используем его, иначе добавляем URL бакета
        const fileUrl = filePath.startsWith('http')
            ? filePath
            : `${BUCKET_URL}/${filePath}`;

        const response = await fetch(fileUrl, {
            method: 'GET',
            headers: {
                'Accept': 'application/json'
            }
        });

        if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }

        const jsonContent = await response.json();
        return jsonContent;

    } catch (error) {
        console.error(`❌ Ошибка загрузки файла ${filePath}:`, error);
        return null;
    }
};

// Функция для загрузки конкретного файла по имени
export const fetchSingleFile = async (fileName) => {
    try {
        const filePath = `${REPORTS_FOLDER}${fileName}`;
        return await loadSingleFile(filePath);
    } catch (error) {
        console.error(`❌ Ошибка загрузки ${fileName}:`, error);
        return null;
    }
};

// Функция для обновления манифеста (если нужно добавлять новые файлы)
export const updateManifest = async (newFilePaths) => {
    try {
        // Загружаем текущий манифест
        const response = await fetch(MANIFEST_URL);
        const currentManifest = await response.json();

        let fileList = [];
        if (Array.isArray(currentManifest)) {
            fileList = currentManifest;
        } else if (currentManifest.files) {
            fileList = currentManifest.files;
        }

        // Добавляем новые файлы (избегая дубликатов)
        for (const newFile of newFilePaths) {
            if (!fileList.includes(newFile)) {
                fileList.push(newFile);
            }
        }

        // Здесь нужно отправить обновленный манифест обратно в S3
        // Обычно это делается через бэкенд API, так как с фронтенда нельзя писать в S3
        console.log('Обновленный список файлов:', fileList);

        // Возвращаем новый список для ручного обновления
        return fileList;

    } catch (error) {
        console.error('Ошибка обновления манифеста:', error);
        return [];
    }
};

// Вспомогательная функция для получения метаданных манифеста
export const getManifestInfo = async () => {
    try {
        const response = await fetch(MANIFEST_URL);

        if (!response.ok) {
            return {
                exists: false,
                status: response.status,
                error: `HTTP ${response.status}`
            };
        }

        const manifest = await response.json();

        let fileCount = 0;
        if (Array.isArray(manifest)) {
            fileCount = manifest.length;
        } else if (manifest.files && Array.isArray(manifest.files)) {
            fileCount = manifest.files.length;
        }

        return {
            exists: true,
            status: response.status,
            fileCount: fileCount,
            lastModified: response.headers.get('last-modified'),
            manifest: manifest
        };

    } catch (error) {
        return {
            exists: false,
            error: error.message
        };
    }
};

// Загрузка файлов с прогрессом (для UI)
export const fetchAllJsonFilesWithProgress = async (onProgress) => {
    try {
        const manifestResponse = await fetch(MANIFEST_URL);

        if (!manifestResponse.ok) {
            throw new Error('Манифест не найден');
        }

        const manifest = await manifestResponse.json();
        const fileList = Array.isArray(manifest) ? manifest : manifest.files || [];

        const reports = [];
        for (let i = 0; i < fileList.length; i++) {
            const report = await loadSingleFile(fileList[i]);
            if (report) {
                reports.push(report);
            }

            // Вызываем callback с прогрессом
            if (onProgress) {
                onProgress({
                    current: i + 1,
                    total: fileList.length,
                    fileName: fileList[i].split('/').pop(),
                    loaded: reports.length
                });
            }
        }

        return reports;

    } catch (error) {
        console.error('Ошибка загрузки:', error);
        return [];
    }
};

// mapS3DataToUIFormat остается без изменений
export const mapS3DataToUIFormat = (s3Data) => {
    const fileName = s3Data.audio_file ? s3Data.audio_file.split('/').pop() : 'unknown.mp3';

    let formattedDate = '';
    try {
        const date = new Date(s3Data.timestamp);
        formattedDate = `${date.getDate().toString().padStart(2, '0')}.${(date.getMonth() + 1).toString().padStart(2, '0')}.${date.getFullYear()} ${date.getHours().toString().padStart(2, '0')}:${date.getMinutes().toString().padStart(2, '0')}`;
    } catch (e) {
        formattedDate = new Date().toLocaleString();
    }

    const getTonality = (sentiment) => {
        if (!sentiment) return 'Нейтральная';
        switch (sentiment.toLowerCase()) {
            case 'positive':
                return 'Позитивная';
            case 'negative':
                return 'Негативная';
            default:
                return 'Нейтральная';
        }
    };

    return {
        id: `${fileName}_${Date.now()}_${Math.random()}`,
        fileName: fileName,
        date: formattedDate,
        scores: {
            overall: parseInt(s3Data.analysis?.overall_score) || 0,
            scriptCompliance: parseInt(s3Data.analysis?.script_score) || 0,
            satisfaction: parseInt(s3Data.analysis?.satisfaction_score) || 0,
            tonality: getTonality(s3Data.analysis?.sentiment)
        },
        summary: s3Data.analysis?.summary || "Нет описания",
        problems: s3Data.analysis?.key_issues || [],
        recommendations: s3Data.analysis?.recommendations || [],
        audioDuration: s3Data.audio_duration_seconds,
        transcript: s3Data.transcript,
        rawData: s3Data
    };
};