// Dashboard.jsx
import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Statistic, Empty, Typography, Button, message, Alert, Spin, Badge } from 'antd';
import {
    FileTextOutlined,
    CheckCircleOutlined,
    WarningOutlined,
    StarOutlined,
    SmileOutlined,
    MehOutlined,
    FrownOutlined,
    ReloadOutlined,
    CloudDownloadOutlined,
    SyncOutlined
} from '@ant-design/icons';
import ConversationCard from './ConversationCard';
import { useS3RealtimeData } from './useS3RealtimeData';

const { Title, Text } = Typography;

const Dashboard = ({ lastUploadedFile }) => {
    // Константа с хардкодными данными
    const hardcodedAnalyses = [
        {
            id: 1,
            fileName: "В 1712 году столица.mp3",
            date: "07.04.2026 16:41",
            scores: {
                overall: 1,
                scriptCompliance: 0,
                satisfaction: 1,
                tonality: "Нейтральная"
            },
            summary: "диалог не состоялся, была представлена только историческая информация без контекста",
            problems: [
                "отсутствие диалога",
                "нет взаимодействия с клиентом"
            ],
            recommendations: [
                "уточнить запрос клиента",
                "провести полноценную беседу"
            ]
        },
        {
            id: 2,
            fileName: "консультация_по_тарифу.mp3",
            date: "06.04.2026 14:23",
            scores: {
                overall: 4,
                scriptCompliance: 5,
                satisfaction: 4,
                tonality: "Позитивная"
            },
            summary: "Оператор профессионально проконсультировал клиента по тарифам, помог выбрать оптимальный вариант. Клиент остался доволен обслуживанием.",
            problems: [
                "небольшая задержка с ответом на 2 вопрос"
            ],
            recommendations: [
                "улучшить знание акционных предложений",
                "активнее предлагать дополнительные услуги"
            ]
        },
        {
            id: 3,
            fileName: "рекламация_по_качеству.mp3",
            date: "05.04.2026 11:15",
            scores: {
                overall: 3,
                scriptCompliance: 3,
                satisfaction: 2,
                tonality: "Негативная"
            },
            summary: "Клиент был недоволен качеством услуги, оператор попытался решить проблему, но не проявил достаточно эмпатии.",
            problems: [
                "не извинился за доставленные неудобства",
                "не предложил компенсацию",
                "говорил шаблонными фразами"
            ],
            recommendations: [
                "пройти тренинг по работе с возражениями",
                "использовать технику 'лестница эмпатии'",
                "предлагать конкретные решения проблемы"
            ]
        }
    ];

    // Используем хук для получения данных из S3
    const {
        data: s3Data,
        loading: s3Loading,
        lastUpdate,
        error: s3Error,
        refresh
    } = useS3RealtimeData(hardcodedAnalyses, 10000); // Обновление каждые 10 секунд

    const [stats, setStats] = useState({
        total: 0,
        averageScore: 0,
        excellentCount: 0,
        needsImprovement: 0
    });

    // Объединяем данные: сначала данные из S3 (которые уже с дедупликацией), потом добавляем загруженный файл
    useEffect(() => {
        let allAnalyses = [...s3Data];

        // Добавляем только что загруженный файл, если его еще нет
        if (lastUploadedFile && lastUploadedFile.scores) {
            const exists = allAnalyses.some(a => a.fileName === lastUploadedFile.fileName);
            if (!exists) {
                allAnalyses = [lastUploadedFile, ...allAnalyses];
            }
        }

        calculateStats(allAnalyses);
    }, [s3Data, lastUploadedFile]);

    const calculateStats = (data) => {
        const validData = data.filter(item => item && item.scores && typeof item.scores.overall === 'number');

        const total = validData.length;
        const totalScore = validData.reduce((sum, item) => sum + item.scores.overall, 0);
        const averageScore = total > 0 ? (totalScore / total).toFixed(1) : 0;
        const excellentCount = validData.filter(item => item.scores.overall >= 4).length;
        const needsImprovement = validData.filter(item => item.scores.overall <= 2).length;

        setStats({ total, averageScore, excellentCount, needsImprovement });
    };

    const getScoreColor = (score) => {
        if (score >= 4) return '#52c41a';
        if (score >= 3) return '#faad14';
        return '#ff4d4f';
    };

    // Компонент индикатора обновления
    const UpdateIndicator = () => (
        <div style={{ position: 'fixed', bottom: 20, right: 20, zIndex: 1000 }}>
            <Badge status={s3Loading ? "processing" : "success"} text={
                s3Loading ? "Обновление..." :
                    lastUpdate ? `Обновлено: ${lastUpdate.toLocaleTimeString()}` : "Готово"
            } />
        </div>
    );

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
                <Title level={3} style={{ margin: 0 }}>
                    Дашборт результатов проверок
                </Title>
                <Button
                    icon={<ReloadOutlined spin={s3Loading} />}
                    onClick={refresh}
                    loading={s3Loading}
                >
                    Обновить из S3
                </Button>
            </div>

            {/* Индикатор автобновления */}
            <div style={{ marginBottom: 16 }}>
                <Text type="secondary">
                    <SyncOutlined spin={s3Loading} />
                    Автообновление каждые 10 секунд {lastUpdate && `(последнее: ${lastUpdate.toLocaleTimeString()})`}
                </Text>
            </div>

            {/* Ошибка при загрузке */}
            {s3Error && (
                <Alert
                    message="Ошибка загрузки из S3"
                    description={s3Error}
                    type="error"
                    showIcon
                    closable
                    style={{ marginBottom: 16 }}
                />
            )}

            {/* Статистика */}
            <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
                <Col xs={24} sm={12} md={12} lg={6}>
                    <Card className="stat-card">
                        <Statistic
                            title="Всего проверок"
                            value={stats.total}
                            prefix={<FileTextOutlined />}
                            valueStyle={{ color: '#1890ff' }}
                        />
                    </Card>
                </Col>
                <Col xs={24} sm={12} md={12} lg={6}>
                    <Card className="stat-card">
                        <Statistic
                            title="Средняя оценка"
                            value={stats.averageScore}
                            suffix="/5"
                            prefix={<StarOutlined />}
                            valueStyle={{ color: getScoreColor(stats.averageScore) }}
                        />
                    </Card>
                </Col>
                <Col xs={24} sm={12} md={12} lg={6}>
                    <Card className="stat-card">
                        <Statistic
                            title="Отличные проверки (4-5)"
                            value={stats.excellentCount}
                            prefix={<CheckCircleOutlined />}
                            valueStyle={{ color: '#52c41a' }}
                        />
                    </Card>
                </Col>
                <Col xs={24} sm={12} md={12} lg={6}>
                    <Card className="stat-card">
                        <Statistic
                            title="Требуют улучшения (1-2)"
                            value={stats.needsImprovement}
                            prefix={<WarningOutlined />}
                            valueStyle={{ color: '#ff4d4f' }}
                        />
                    </Card>
                </Col>
            </Row>

            {/* Список карточек проверок */}
            <Spin spinning={s3Loading && s3Data.length === 0} tip="Загрузка данных из S3...">
                <Row gutter={[16, 16]}>
                    {s3Data.length > 0 ? (
                        s3Data.map((analysis) => (
                            analysis && analysis.scores ? (
                                <Col xs={24} lg={12} xl={8} key={analysis.id}>
                                    <ConversationCard analysis={analysis} />
                                </Col>
                            ) : null
                        ))
                    ) : (
                        <Col span={24}>
                            <Empty description="Нет результатов проверок" />
                        </Col>
                    )}
                </Row>
            </Spin>

            <UpdateIndicator />
        </div>
    );
};

export default Dashboard;